### MainActivity 
```kotlin
class MainActivity : AbcvlibActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
    }

    override fun onSerialReady(usbSerial: UsbSerial) {
        super.onSerialReady(usbSerial)
        initPython()
    }

    private fun initPython() {
        if (!Python.isStarted()) {
            Python.start(AndroidPlatform(this))
        }

        val py = Python.getInstance()
        val setupModule = py.getModule("abcvlib")
        // inject variables to python
        setupModule.put("outputs", outputs)
        setupModule.put("loop_delay", 0.005) // 5 ms

        lifecycleScope.launch(Dispatchers.Default) {
            try {
                setupModule.callAttr("run")
            } catch (e: PyException) {
                Logger.e("MainActivity", "Python error: ${e.message}")
            }
        }
    }
}
```
### python/abcvlib.py
This module acts as the bridge between Android and the Python control logic.
```python
import time
import builtins
import main

outputs = None
loop_delay = 0.010


def run():
    builtins.outputs = outputs  # expose AbcvlibActivity.outputs to main.py

    main.setup()
    print("setup done")

    print("start main-loop with dealy", loop_delay)
    while True:
        main.loop()
        time.sleep(loop_delay)
```

### python/main.py
The actual app logic.
```python
speed = 0.0
increment = 0.4

def setup():
    print("Hello World!")

def loop():
    global speed, increment
    outputs.setWheelOutput(speed, speed, False, False)

    if speed >= 1.0 or speed <= -1.0:
        increment = -increment
    speed += increment
```

